VALUES
  ('social-worker-moex-07970', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '對於政府與非營利組織之間的互動關係大致朝向夥伴關係及關係式契約的發展，尤其是後者，就此學者 Schwartz 則提到關係型的委外要求是適合於社會服務的領域，但其內在卻有著若干風險存在，下列何者 不屬此範圍？', '["信任的濫用", "過度的深植", "政治監督", "對資源的錯誤期待"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07971', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '因應社會的變遷，連公司也變得「去工作化」，工作的意義也被模糊，甚至有所謂無職務的工作環境趨 勢出現，要達到此境界包括下列幾個策略，其中何者並不屬於此範圍？', '["組織扁平化", "工作團隊", "無邊界組織", "工作改善"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07972', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '擔任社會工作管理者是需要有其應有的認知，下列各項何者不屬於該內容？', '["組織的管理是每個人的工作", "管理和服務是相互影響的", "好的管理者兼具概念性、技術性與人群關係的技巧", "最佳的直接服務者必然是成功的管理者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07973', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會福利機構或組織因提供福利服務的需要而需善用社會資源，為使這些社會資源能有效運用，資源管 理是必要的工作。然資源管理包括四個重要因素，下列何者不是該要素？', '["資源盤點", "資源轉介", "資源維繫", "資源開發"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07974', 'social-worker', 'social-worker-moex-099-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '面對未來相關社會福利法規將會賦予社工更多的職責以及服務對象自身權利意識也將會提升，機構若要 降低工作員違反社會工作倫理的風險，就要做的工作是什麼？', '["社會工作倫理守則的修訂或新訂", "專業團體開始籌設制度化的倫理委員會", "建立涉及或非涉及法律面的倫理規範要有相關配套", "要做倫理的風險管理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "26b119d33aac", "answer_pdf_sha1": "6450e194dcb4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "400", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07975', 'social-worker', 'social-worker-moex-099-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試社會工作師考試試題 類       科：社會工作師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "70c57bb48ee5", "answer_pdf_sha1": "4f4489e8c0c3", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 99, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
